const parentRoute = getRouteApi("/compete/organizer/$competitionId")

// Search schema for URL state
const submissionsSearchSchema = z.object({
	division: z.string().optional(),
	status: z.enum(["all", "pending", "reviewed"]).optional(),
	sort: z.enum(["newest", "oldest", "athlete", "division", "score"]).optional(),
})

export const Route = createFileRoute(
	"/compete/organizer/$competitionId/events/$eventId/submissions/",
)({
	component: SubmissionsPage,
	validateSearch: submissionsSearchSchema,
	loaderDeps: ({ search }) => ({
		division: search?.division,
		status: search?.status,
	}),
	loader: async ({ params, deps }) => {
		// First get competition to know the teamId
		const { competition } = await getCompetitionByIdFn({
			data: { competitionId: params.competitionId },
		})

		if (!competition) {
			throw new Error("Competition not found")
		}

		// Only allow for online competitions
		if (competition.competitionType !== "online") {
			throw new Error(
				"Video submissions are only available for online competitions",
			)
		}

		// Parallel fetch event details, divisions, and submissions
		const [eventResult, divisionsResult, submissionsResult] = await Promise.all(
			[
				getCompetitionEventFn({
					data: {
						trackWorkoutId: params.eventId,
						teamId: competition.organizingTeamId,
					},
				}),
				getCompetitionDivisionsWithCountsFn({
					data: {
						competitionId: params.competitionId,
						teamId: competition.organizingTeamId,
					},
				}),
				getOrganizerSubmissionsFn({
					data: {
						trackWorkoutId: params.eventId,
						competitionId: params.competitionId,
						divisionFilter: deps?.division,
						statusFilter: deps?.status,
					},
				}),
			],
		)

		if (!eventResult.event) {
			throw new Error("Event not found")
		}

		return {
			event: eventResult.event,
			divisions: divisionsResult.divisions,
			submissions: submissionsResult.submissions,
			totals: submissionsResult.totals,
			currentDivisionFilter: deps?.division,
			currentStatusFilter: deps?.status || "all",
		}
	},
})

function SubmissionsPage() {
	const {
		event,
		divisions,
		submissions,
		totals,
		currentDivisionFilter,
		currentStatusFilter,
	} = Route.useLoaderData()
	const { competition } = parentRoute.useLoaderData()
	const navigate = useNavigate()
	const search = Route.useSearch()

	// Local state for sorting (client-side)
	const [sortBy, setSortBy] = useState<string>(search.sort || "newest")

	const handleDivisionChange = (value: string) => {
		navigate({
			to: "/compete/organizer/$competitionId/events/$eventId/submissions",
			params: {
				competitionId: competition.id,
				eventId: event.id,
			},
			search: (prev) => ({
				...prev,
				division: value === "all" ? undefined : value,
			}),
			resetScroll: false,
		})
	}

	const handleStatusChange = (value: string) => {
		navigate({
			to: "/compete/organizer/$competitionId/events/$eventId/submissions",
			params: {
				competitionId: competition.id,
				eventId: event.id,
			},
			search: (prev) => ({
				...prev,
				status: value === "all" ? undefined : (value as "pending" | "reviewed"),
			}),
			resetScroll: false,
		})
	}

	const clearFilters = () => {
		navigate({
			to: "/compete/organizer/$competitionId/events/$eventId/submissions",
			params: {
				competitionId: competition.id,
				eventId: event.id,
			},
			search: {},
			resetScroll: false,
		})
	}

	// Sort submissions client-side
	const sortedSubmissions = [...submissions].sort((a, b) => {
		switch (sortBy) {
			case "newest":
				return (
					new Date(b.submittedAt).getTime() - new Date(a.submittedAt).getTime()
				)
			case "oldest":
				return (
					new Date(a.submittedAt).getTime() - new Date(b.submittedAt).getTime()
				)
			case "athlete": {
				const nameA = `${a.athlete.firstName || ""} ${a.athlete.lastName || ""}`
					.trim()
					.toLowerCase()
				const nameB = `${b.athlete.firstName || ""} ${b.athlete.lastName || ""}`
					.trim()
					.toLowerCase()
				return nameA.localeCompare(nameB)
			}
			case "division": {
				const divA = a.division?.label || ""
				const divB = b.division?.label || ""
				return divA.localeCompare(divB)
			}
			case "score": {
				// Sort by score value, nulls last
				if (a.score?.value === null && b.score?.value === null) return 0
				if (a.score?.value === null) return 1
				if (b.score?.value === null) return -1
				return (a.score?.value || 0) - (b.score?.value || 0)
			}
			default:
				return 0
		}
	})

	const formatDate = (date: Date | string) => {
		return new Date(date).toLocaleDateString(undefined, {
			year: "numeric",
			month: "short",
			day: "numeric",
			hour: "2-digit",
			minute: "2-digit",
		})
	}

	const getInitials = (firstName: string | null, lastName: string | null) => {
		const first = firstName?.[0] || ""
		const last = lastName?.[0] || ""
		return (first + last).toUpperCase() || "?"
	}

	const progressPercentage =
		totals.total > 0 ? Math.round((totals.reviewed / totals.total) * 100) : 0

	const hasActiveFilters =
		currentDivisionFilter ||
		(currentStatusFilter && currentStatusFilter !== "all")

	return (
		<div className="flex flex-col gap-6">
			{/* Header */}
			<div className="flex items-center justify-between">
				<div>
					<h1 className="text-2xl font-bold">Video Submissions</h1>
					<p className="text-muted-foreground">
						Event #{event.trackOrder} - {event.workout.name}
					</p>
				</div>
				<Button asChild variant="outline" size="sm">
					<Link
						to="/compete/organizer/$competitionId/events/$eventId"
						params={{
							competitionId: competition.id,
							eventId: event.id,
						}}
					>
						Back to Event
					</Link>
				</Button>
			</div>

			{/* Progress Card */}
			<Card>
				<CardHeader className="pb-2">
					<CardTitle className="text-lg">Review Progress</CardTitle>
					<CardDescription>
						{totals.reviewed} of {totals.total} submissions reviewed
					</CardDescription>
				</CardHeader>
				<CardContent>
					<div className="flex items-center gap-4">
						<Progress value={progressPercentage} className="flex-1" />
						<span className="text-sm font-medium">{progressPercentage}%</span>
					</div>
					<div className="mt-3 flex gap-4 text-sm">
						<div className="flex items-center gap-2">
							<div className="h-3 w-3 rounded-full bg-green-500" />
							<span>Reviewed: {totals.reviewed}</span>
						</div>
						<div className="flex items-center gap-2">
							<div className="h-3 w-3 rounded-full bg-yellow-500" />
							<span>Pending: {totals.pending}</span>
						</div>
					</div>
				</CardContent>
			</Card>

			{/* Filters */}
			<div className="flex flex-col gap-3">
				<div className="flex flex-wrap items-center gap-3">
					{/* Division filter */}
					<Select
						value={currentDivisionFilter || "all"}
						onValueChange={handleDivisionChange}
					>
						<SelectTrigger className="w-[200px]">
							<SelectValue placeholder="All Divisions" />
						</SelectTrigger>
						<SelectContent>
							<SelectItem value="all">All Divisions</SelectItem>
							{divisions.map((division) => (
								<SelectItem key={division.id} value={division.id}>
									{division.label}
								</SelectItem>
							))}
						</SelectContent>
					</Select>

					{/* Status filter */}
					<Select
						value={currentStatusFilter || "all"}
						onValueChange={handleStatusChange}
					>
						<SelectTrigger className="w-[180px]">
							<SelectValue placeholder="All Status" />
						</SelectTrigger>
						<SelectContent>
							<SelectItem value="all">All Status</SelectItem>
							<SelectItem value="pending">Pending Review</SelectItem>
							<SelectItem value="reviewed">Reviewed</SelectItem>
						</SelectContent>
					</Select>

					{/* Sort */}
					<Select value={sortBy} onValueChange={setSortBy}>
						<SelectTrigger className="w-[180px]">
							<SelectValue placeholder="Sort by" />
						</SelectTrigger>
						<SelectContent>
							<SelectItem value="newest">Newest First</SelectItem>
							<SelectItem value="oldest">Oldest First</SelectItem>
							<SelectItem value="athlete">Athlete Name</SelectItem>
							<SelectItem value="division">Division</SelectItem>
							<SelectItem value="score">Score</SelectItem>
						</SelectContent>
					</Select>

					{/* Clear filters */}
					{hasActiveFilters && (
						<Button
							variant="ghost"
							size="sm"
							onClick={clearFilters}
							className="gap-1"
						>
							<X className="h-4 w-4" />
							Clear Filters
						</Button>
					)}
				</div>

				{/* Active filter pills */}
				{hasActiveFilters && (
					<div className="flex flex-wrap items-center gap-2">
						{currentDivisionFilter && (
							<Badge
								variant="secondary"
								className="pl-2 pr-1 py-1 flex items-center gap-1"
							>
								<span className="text-xs text-muted-foreground">Division:</span>
								<span>
									{divisions.find((d) => d.id === currentDivisionFilter)
										?.label || currentDivisionFilter}
								</span>
								<button
									type="button"
									onClick={() => handleDivisionChange("all")}
									className="ml-1 hover:bg-muted rounded-full p-0.5"
								>
									<X className="h-3 w-3" />
								</button>
							</Badge>
						)}
						{currentStatusFilter && currentStatusFilter !== "all" && (
							<Badge
								variant="secondary"
								className="pl-2 pr-1 py-1 flex items-center gap-1"
							>
								<span className="text-xs text-muted-foreground">Status:</span>
								<span className="capitalize">{currentStatusFilter}</span>
								<button
									type="button"
									onClick={() => handleStatusChange("all")}
									className="ml-1 hover:bg-muted rounded-full p-0.5"
								>
									<X className="h-3 w-3" />
								</button>
							</Badge>
						)}
					</div>
				)}
			</div>

			{/* Submissions Table */}
			{sortedSubmissions.length === 0 ? (
				<Card>
					<CardHeader>
						<CardTitle>No Submissions</CardTitle>
						<CardDescription>
							{hasActiveFilters
								? "No submissions match the current filters."
								: "No video submissions have been received for this event yet."}
						</CardDescription>
					</CardHeader>
				</Card>
			) : (
				<Card>
					<CardContent className="p-0">
						<Table>
							<TableHeader>
								<TableRow>
									<TableHead className="w-[50px]">#</TableHead>
									<TableHead>Athlete</TableHead>
									<TableHead>Division</TableHead>
									<TableHead>Claimed Score</TableHead>
									<TableHead>
										<span className="flex items-center gap-1">
											<Calendar className="h-3.5 w-3.5" />
											Submitted
										</span>
									</TableHead>
									<TableHead>Video</TableHead>
									<TableHead>Status</TableHead>
									<TableHead className="w-[100px]">Action</TableHead>
								</TableRow>
							</TableHeader>
							<TableBody>
								{sortedSubmissions.map((submission, index) => (
									<TableRow
										key={submission.id}
										className="cursor-pointer hover:bg-muted/50"
									>
										<TableCell className="font-mono text-sm text-muted-foreground">
											{index + 1}
										</TableCell>
										<TableCell>
											<div className="flex items-center gap-3">
												<Avatar className="h-8 w-8">
													<AvatarImage
														src={submission.athlete.avatar ?? undefined}
														alt={`${submission.athlete.firstName ?? ""} ${submission.athlete.lastName ?? ""}`}
													/>
													<AvatarFallback className="text-xs">
														{getInitials(
															submission.athlete.firstName,
															submission.athlete.lastName,
														)}
													</AvatarFallback>
												</Avatar>
												<div className="flex flex-col">
													<span className="font-medium">
														{submission.athlete.firstName ?? ""}{" "}
														{submission.athlete.lastName ?? ""}
													</span>
													{submission.teamName && (
														<span className="text-xs text-muted-foreground">
															{submission.teamName}
														</span>
													)}
												</div>
											</div>
										</TableCell>
										<TableCell>
											{submission.division ? (
												<Badge variant="outline">
													{submission.division.label}
												</Badge>
											) : (
												<span className="text-muted-foreground">—</span>
											)}
										</TableCell>
										<TableCell>
											{submission.score?.displayScore ? (
												<span className="font-mono">
													{submission.score.displayScore}
													{submission.score.status === "cap" && (
														<span className="ml-1 text-xs text-muted-foreground">
															(cap)
														</span>
													)}
												</span>
											) : (
												<span className="text-muted-foreground">—</span>
											)}
										</TableCell>
										<TableCell className="text-muted-foreground text-sm">
											{formatDate(submission.submittedAt)}
										</TableCell>
										<TableCell>
											<a
												href={submission.videoUrl}
												target="_blank"
												rel="noopener noreferrer"
												className="inline-flex items-center gap-1 text-sm text-primary hover:underline"
												onClick={(e) => e.stopPropagation()}
											>
												<Play className="h-3.5 w-3.5" />
												Watch
												<ExternalLink className="h-3 w-3" />
											</a>
										</TableCell>
										<TableCell>
											{submission.reviewStatus === "reviewed" ? (
												<Badge variant="default" className="gap-1 bg-green-600">
													<CheckCircle2 className="h-3 w-3" />
													Reviewed
												</Badge>
											) : (
												<Badge variant="secondary" className="gap-1">
													<Clock className="h-3 w-3" />
													Pending
												</Badge>
											)}
										</TableCell>
										<TableCell>
											<Link
												to="/compete/organizer/$competitionId/events/$eventId/submissions/$submissionId"
												params={{
													competitionId: competition.id,
													eventId: event.id,
													submissionId: submission.id,
												}}
												onClick={(e) => e.stopPropagation()}
											>
												<Button variant="outline" size="sm">
													Review
												</Button>
											</Link>
										</TableCell>
									</TableRow>
								))}
							</TableBody>
						</Table>
					</CardContent>
				</Card>
			)}
		</div>
	)
}

/**
 * Organizer Video Submission Review Detail Route
 *
 * Single submission review page where organizers can watch the video,
 * see the claimed score, and mark as reviewed.
 */

import { useState } from "react"
import {
	createFileRoute,
	getRouteApi,
	Link,
	useRouter,
} from "@tanstack/react-router"
import { useServerFn } from "@tanstack/react-start"
import {
	ArrowLeft,
	Calendar,
	CheckCircle2,
	Clock,
	ExternalLink,
	FileText,
	Trophy,
	Undo2,
	User,
} from "lucide-react"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
	Card,
	CardContent,
	CardDescription,
	CardHeader,
	CardTitle,
} from "@/components/ui/card"
import { Separator } from "@/components/ui/separator"
import { YouTubeEmbed, isYouTubeUrl } from "@/components/compete/youtube-embed"
import { isSafeUrl } from "@/utils/url"
import {
	getOrganizerSubmissionDetailFn,
	markSubmissionReviewedFn,
	unmarkSubmissionReviewedFn,
} from "@/server-fns/video-submission-fns"

const parentRoute = getRouteApi("/compete/organizer/$competitionId")

export const Route = createFileRoute(
	"/compete/organizer/$competitionId/events/$eventId/submissions/$submissionId",
)({
	component: SubmissionDetailPage,
	loader: async ({ params }) => {
		const result = await getOrganizerSubmissionDetailFn({
			data: {
				submissionId: params.submissionId,
				competitionId: params.competitionId,
			},
		})

		if (!result.submission) {
			throw new Error("Submission not found")
		}

		return { submission: result.submission }
	},
})

function SubmissionDetailPage() {
	const { submission } = Route.useLoaderData()
	const { competition } = parentRoute.useLoaderData()
	const params = Route.useParams()
	const router = useRouter()

	const markReviewed = useServerFn(markSubmissionReviewedFn)
	const unmarkReviewed = useServerFn(unmarkSubmissionReviewedFn)

	const [isUpdating, setIsUpdating] = useState(false)

	const isReviewed = submission.reviewStatus === "reviewed"
	const isYouTube = isYouTubeUrl(submission.videoUrl)

	const handleToggleReview = async () => {
		setIsUpdating(true)
		try {
			if (isReviewed) {
				await unmarkReviewed({
					data: { submissionId: submission.id, competitionId: competition.id },
				})
			} else {
				await markReviewed({
					data: { submissionId: submission.id, competitionId: competition.id },
				})
			}
			router.invalidate()
		} finally {
			setIsUpdating(false)
		}
	}

	const formatDate = (date: Date | string) => {
		return new Date(date).toLocaleDateString(undefined, {
			year: "numeric",
			month: "short",
			day: "numeric",
			hour: "2-digit",
			minute: "2-digit",
		})
	}

	const getInitials = (firstName: string | null, lastName: string | null) => {
		const first = firstName?.[0] || ""
		const last = lastName?.[0] || ""
		return (first + last).toUpperCase() || "?"
	}

	return (
		<div className="flex flex-col gap-6">
			{/* Header */}
			<div className="flex items-center justify-between">
				<div className="flex items-center gap-3">
					<Link
						to="/compete/organizer/$competitionId/events/$eventId/submissions"
						params={{
							competitionId: competition.id,
							eventId: params.eventId,
						}}
					>
						<Button variant="ghost" size="icon">
							<ArrowLeft className="h-4 w-4" />
						</Button>
					</Link>
					<div>
						<h1 className="text-2xl font-bold">Review Submission</h1>
						<p className="text-muted-foreground">
							{submission.athlete.firstName} {submission.athlete.lastName}
						</p>
					</div>
				</div>

				{/* Review action */}
				{isReviewed ? (
					<Button
						variant="outline"
						onClick={handleToggleReview}
						disabled={isUpdating}
						className="gap-2"
					>
						<Undo2 className="h-4 w-4" />
						{isUpdating ? "Updating..." : "Unmark Reviewed"}
					</Button>
				) : (
					<Button
						onClick={handleToggleReview}
						disabled={isUpdating}
						className="gap-2 bg-green-600 hover:bg-green-700"
					>
						<CheckCircle2 className="h-4 w-4" />
						{isUpdating ? "Updating..." : "Mark as Reviewed"}
					</Button>
				)}
			</div>

			{/* Status banner */}
			{isReviewed ? (
				<div className="rounded-lg border border-green-500/30 bg-green-500/10 px-4 py-3">
					<div className="flex items-center gap-2">
						<CheckCircle2 className="h-4 w-4 text-green-600 dark:text-green-400" />
						<p className="text-sm text-green-700 dark:text-green-300">
							This submission has been reviewed
							{submission.reviewedAt && (
								<span className="ml-1 text-green-600/70 dark:text-green-400/70">
									on {formatDate(submission.reviewedAt)}
								</span>
							)}
						</p>
					</div>
				</div>
			) : (
				<div className="rounded-lg border border-yellow-500/30 bg-yellow-500/10 px-4 py-3">
					<div className="flex items-center gap-2">
						<Clock className="h-4 w-4 text-yellow-600 dark:text-yellow-400" />
						<p className="text-sm text-yellow-700 dark:text-yellow-300">
							This submission is pending review
						</p>
					</div>
				</div>
			)}

			<div className="grid gap-6 lg:grid-cols-3">
				{/* Video - takes 2 columns */}
				<div className="lg:col-span-2">
					<Card>
						<CardHeader>
							<CardTitle>Video</CardTitle>
						</CardHeader>
						<CardContent>
							{isYouTube ? (
								<YouTubeEmbed
									url={submission.videoUrl}
									title="Submission video"
								/>
							) : (
								<div className="rounded-lg border bg-muted/50 p-6">
									<div className="flex items-center gap-3">
										<FileText className="h-5 w-5 text-muted-foreground" />
										<div className="flex-1 min-w-0">
											<p className="text-sm font-medium truncate">
												{submission.videoUrl}
											</p>
											<p className="text-xs text-muted-foreground">
												External video link
											</p>
										</div>
										<a
											href={
												isSafeUrl(submission.videoUrl)
													? submission.videoUrl
													: "#"
											}
											target="_blank"
											rel="noopener noreferrer"
											className="flex items-center gap-1.5 text-sm text-primary hover:underline shrink-0"
										>
											<ExternalLink className="h-4 w-4" />
											Open
										</a>
									</div>
								</div>
							)}

							{/* Direct link below embed */}
							{isYouTube && (
								<div className="mt-3">
									<a
										href={
											isSafeUrl(submission.videoUrl)
												? submission.videoUrl
												: "#"
										}
										target="_blank"
										rel="noopener noreferrer"
										className="inline-flex items-center gap-1.5 text-sm text-muted-foreground hover:text-primary"
									>
										<ExternalLink className="h-3.5 w-3.5" />
										Open in YouTube
									</a>
								</div>
							)}
						</CardContent>
					</Card>

					{/* Notes */}
					{submission.notes && (
						<Card className="mt-6">
							<CardHeader>
								<CardTitle>Athlete Notes</CardTitle>
							</CardHeader>
							<CardContent>
								<p className="text-sm whitespace-pre-wrap">
									{submission.notes}
								</p>
							</CardContent>
						</Card>
					)}
				</div>

				{/* Sidebar */}
				<div className="flex flex-col gap-6">
					{/* Athlete info */}
					<Card>
						<CardHeader>
							<CardTitle className="flex items-center gap-2">
								<User className="h-4 w-4" />
								Athlete
							</CardTitle>
						</CardHeader>
						<CardContent>
							<div className="flex items-center gap-3">
								<Avatar className="h-10 w-10">
									<AvatarImage
										src={submission.athlete.avatar ?? undefined}
										alt={`${submission.athlete.firstName ?? ""} ${submission.athlete.lastName ?? ""}`}
									/>
									<AvatarFallback>
										{getInitials(
											submission.athlete.firstName,
											submission.athlete.lastName,
										)}
									</AvatarFallback>
								</Avatar>
								<div>
									<p className="font-medium">
										{submission.athlete.firstName}{" "}
										{submission.athlete.lastName}
									</p>
									<p className="text-sm text-muted-foreground">
										{submission.athlete.email}
									</p>
								</div>
							</div>

							{submission.teamName && (
								<>
									<Separator className="my-3" />
									<p className="text-sm">
										<span className="text-muted-foreground">Team: </span>
										{submission.teamName}
									</p>
								</>
							)}

							{submission.division && (
								<>
									<Separator className="my-3" />
									<p className="text-sm">
										<span className="text-muted-foreground">Division: </span>
										<Badge variant="outline" className="ml-1">
											{submission.division.label}
										</Badge>
									</p>
								</>
							)}
						</CardContent>
					</Card>

					{/* Claimed score */}
					<Card>
						<CardHeader>
							<CardTitle className="flex items-center gap-2">
								<Trophy className="h-4 w-4 text-amber-500" />
								Claimed Score
							</CardTitle>
							<CardDescription>Self-reported by athlete</CardDescription>
						</CardHeader>
						<CardContent>
							{submission.score?.displayScore ? (
								<div>
									<p className="text-3xl font-mono font-bold">
										{submission.score.displayScore}
									</p>
									{submission.score.status === "cap" && (
										<Badge variant="secondary" className="mt-2">
											Capped
										</Badge>
									)}
								</div>
							) : (
								<p className="text-muted-foreground">No score submitted</p>
							)}
						</CardContent>
					</Card>

					{/* Submission metadata */}
					<Card>
						<CardHeader>
							<CardTitle className="flex items-center gap-2">
								<Calendar className="h-4 w-4" />
								Submission Info
							</CardTitle>
						</CardHeader>
						<CardContent className="space-y-2 text-sm">
							<div className="flex justify-between">
								<span className="text-muted-foreground">Submitted</span>
								<span>{formatDate(submission.submittedAt)}</span>
							</div>
							<div className="flex justify-between">
								<span className="text-muted-foreground">Status</span>
								{isReviewed ? (
									<Badge
										variant="default"
										className="gap-1 bg-green-600"
									>
										<CheckCircle2 className="h-3 w-3" />
										Reviewed
									</Badge>
								) : (
									<Badge variant="secondary" className="gap-1">
										<Clock className="h-3 w-3" />
										Pending
									</Badge>
								)}
							</div>
						</CardContent>
					</Card>
				</div>
			</div>
		</div>
	)
}

